var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"SCN No. TPM001M000139-05\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 인터뷰","JPN":"SCN No. TPM001M000139-05\\n<color=#ffd34c>3級要人</color>閲覧承認資料\\n付録：インタビュー","ENG":"SCN No. TPM001M000139-05\\n<color=#ffd34c>Clearance Level III</color> Classified Information\\nAnnex: Interview","TWN":"SCN No.TPM001M000139-05\\n<color=#ffd34c>3級要員</color> 閱覽審批資料\\n附錄採訪"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"제가 왜 경찰에 지원했냐고요?","JPN":"私が警察になった理由ですか？","ENG":"Why did I apply to the police, you ask?","TWN":"你問我為什麼要當警察？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아하하, 그야 공무원이니까 그렇겠죠?","JPN":"あはは、公務員だからですね。","ENG":"Hah hah, well I guess because I thought being a government employee would mean a stable living.","TWN":"哈哈哈，當然是因為警察是公務員啊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아빠가 명예퇴직 하시고 나서 항상 직장은 철밥통이 최고라고 노래를 부르셨거든요.","JPN":"父が退職した後、公務員が一番だといつも言っていたので。","ENG":"At least that's what my dad always said, ever since he was laid off from his job.","TWN":"我爸榮譽退休後，就一直在讚說「鐵飯碗最棒了」。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"음, 굳이 저에게 다른 이유를 물으신다면......","JPN":"うーむ、他の理由は……","ENG":"Hmm... But if you really must know why else...","TWN":"嗯，真要說有什麼其他理由的話……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"합법적으로 공공도로를 질주할 수 있어서 랄까요?","JPN":"合法的に道路を爆走できるからでしょうか？","ENG":"I guess it's because I can legally speed?","TWN":"因為可以在公路上合法地超速行駛？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"솔직히 말해서, 그거야말로 경찰만이 할 수 있는 일이잖아요?","JPN":"正直なところ、それこそ警察にしかできないことでしょう？","ENG":"I mean, that is like the one thing that only cops get to do.","TWN":"說真的，這只有警察才能做到吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"보통 사람이 과속을 하면 불법이지만 범죄자를 추적하는 경찰이 속도를 내는 건 당연한 의무니까요.","JPN":"普通の人なら違法ですけど、犯罪者を追跡する警察がスピードを出すのは義務なので。","ENG":"It's illegal for civilians to speed, but it's a police officer's duty to step on the gas to catch criminals.","TWN":"畢竟一般人超速是違法的，但警察為了追捕嫌犯超速，卻是理所當然的義務啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런 점이 좋은 거죠. 그렇게 실적을 쌓아서 얻는 직업적 성취감은 덤이고요.","JPN":"そういう点がいいんです。そうやって実績を積むことで感じられる働き甲斐は、おまけみたいなものです。","ENG":"So that's a great perk for me. The sense of professional pride and fulfillment from catching bad guys is a bonus.","TWN":"我就是喜歡這點。累積業績、獲得工作成就感，這些都只額外附贈的東西。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하아, 그런데 그런 것도 적당해야 할만한 건데 말이에요.","JPN":"はあ、ほどほどにしてくれないと困るんですよね。","ENG":"But like they say, everything in moderation would be better.","TWN":"唉，但凡事都該有個度嘛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"몇 년째 인력충원도 안되고, 허구한날 사건사고만 터져대니까 그건 그거대로 피곤해지더라고요.","JPN":"ここ数年新入りは来ないし、毎日事件に追われてばかりで、ちょっと疲れちゃいました。","ENG":"It's been years since we got any extra personnel, while the cases keep piling up. That can get real exhausting real quick.","TWN":"我們好幾年沒進新人了，還一直發生各式各樣的事件，整得我都有點累了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 그렇다고 딱히 일을 관두고 싶단 생각은 해본 적 없어요.","JPN":"あ、だからといって警察をやめたいわけじゃありません。","ENG":"Then again, I never really thought about quitting either.","TWN":"啊，但我從沒有要放棄工作的想法喔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"역시 경찰만큼 체질에 맞는 일도 없는 것 같고, 뭣보다......","JPN":"やっぱり警察が一番性に合ってますし、何より……","ENG":"I think being a cop suits me better than any other job. And most of all...","TWN":"沒有比警察更適合我的工作，而且啊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"요즘엔 세상물정 모르는 왈가닥 꼬마 경정님 가르치는 재미로 일하고 있거든요.","JPN":"最近は世間知らずな、じゃじゃ馬チビ警視様を教えるのが楽しいので。","ENG":"I'm having too much fun showing the ropes to a cute but clueless major these days.","TWN":"最近教育那個不懂待人處世的小不點警正，非常有樂趣喔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......누가 왈가닥 꼬마 경정이지?! 강소영 경위!","JPN":"……誰がじゃじゃ馬チビ警視ですって！　マエカワ警部補！","ENG":"Who are you calling cute but clueless?! Lieutenant Kang!","TWN":"……妳說誰是小不點警正啊？姜素英警衛！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"와, 들렸나 보네. 역시 카운터라서 그런지 귀도 밝으시다니까요.","JPN":"わあ、聞こえちゃったみたいですね。やっぱりカウンターだからでしょうか。","ENG":"Oh, I guess she heard me. Super hearing must be one of her Counter abilities or something.","TWN":"哇，被聽到了。不愧是制裁者，耳朵這麼靈。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"저는 이만, 밀린 업무가 많아서 가봐야겠어요.","JPN":"それじゃあ、私は溜まってる仕事があるので。","ENG":"Anyway, I'd better go catch up on my work now.","TWN":"那麼，我還有很多公事要辦，就先告辭了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 혹시 이 인터뷰, 진급 심사에 반영되는 건 아니겠죠?","JPN":"ところでこのインタビュー、昇級審査に響いたりしませんよね？","ENG":"By the way... This interview's not going to affect my promotion, is it?","TWN":"話說，這個採訪不會影響到晉升審查吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};